// src/pages/Home.js
import React from 'react';
import { useNavigate } from 'react-router-dom';
import './Home.css';

function Home() {
  const navigate = useNavigate();

  const handleRegular = () => {
    navigate('/images', { state: { mode: 'regular' } });
  };

  const handleSegmentation = () => {
    navigate('/images', { state: { mode: 'segmentation' } });
  };

  return (
    <div className="home-container">
      <div className="home-card">
        <h1>Annotation website</h1>
        <p>Annotate images with bounding boxes, polygons, and more.</p>
        <div className="home-buttons">
          <button className="primary-button" onClick={handleRegular}>
            Image Annotation
          </button>
          <button className="primary-button" onClick={handleSegmentation}>
            Image Segmentation
          </button>
        </div>
      </div>
    </div>
  );
}

export default Home;
